mapper.sql:
SELECT T.ID, T.ORDER_SN, T.USER_ID, U.NICKNAME USER_NICKNAME, T.ORDER_STATUS, T.SHIPPING_STATUS, T.PAY_STATUS, T.CONSIGNEE, T.COUNTRY, T.PROVINCE, T.CITY, T.DISTRICT, T.ADDRESS, T.MOBILE, T.POSTSCRIPT, T.SHIPPING_ID, T.SHIPPING_NAME, T.PAY_ID, T.PAY_NAME, T.SHIPPING_FEE, T.ACTUAL_PRICE, T.INTEGRAL, T.INTEGRAL_MONEY, T.ORDER_PRICE, T.GOODS_PRICE, T.ADD_TIME, T.CONFIRM_TIME, T.PAY_TIME, T.FREIGHT_PRICE, T.COUPON_ID, T.PARENT_ID, T.COUPON_PRICE, T.CALLBACK_STATUS, T.SHIPPING_NO, T.FULL_CUT_PRICE, T.ORDER_TYPE FROM MALL_ORDER T LEFT JOIN MALL_USER U ON U.ID = T.USER_ID WHERE 1=1
AND T.ID = #{params.id}
AND T.ORDER_SN LIKE '%${params.orderSn}%'
AND T.USER_ID = #{params.userId}
AND U.NICKNAME LIKE '%${params.nickname}%'
AND T.ORDER_STATUS = #{params.orderStatus}

mapper.select:
select * from mall_order


        and user_id = #{userId}




        order by ${sidx} ${order}


        order by id desc



    limit #{offset}, #{limit}
